/// <summary>
///  The <c>ETGOTMSalesLineWritePostSuperOutputContract</c> class is used as data contract for the <c>SalesTableForm</c> class.
/// </summary>
class ETGOTMSalesLineWritePostSuperOutputContract implements SysPackable
{
    boolean                 creditNoteCashDiscMessage;
    boolean                 salesTableCheckUpdate;
    boolean                 retailSumLinesHasChanged;

    #define.CurrentVersion(1)

    #localmacro.CurrentList
        creditNoteCashDiscMessage,
        salesTableCheckUpdate,
        retailSumLinesHasChanged
    #endmacro

}

Method.Source:
public boolean parmCreditNoteCashDiscMessage(boolean _creditNoteCashDiscMessage = creditNoteCashDiscMessage)
{
    creditNoteCashDiscMessage = _creditNoteCashDiscMessage;
    return creditNoteCashDiscMessage;
}

public boolean parmPurchTableCheckUpdate (boolean _salesTableCheckUpdate = salesTableCheckUpdate)
{
    salesTableCheckUpdate = _salesTableCheckUpdate;
    return salesTableCheckUpdate;
}

public boolean parmRetailSumLinesHasChanged(boolean _retailSumLinesHasChanged = retailSumLinesHasChanged)
{
    retailSumLinesHasChanged = _retailSumLinesHasChanged;
    return retailSumLinesHasChanged;
}

public boolean unpack(container _packedClass)
{
    int version     = RunBase::getVersion(_packedClass);

    switch (version)
    {
        case #CurrentVersion:
            [version,#CurrentList] = _packedClass;
            return true;
        default :
            return false;
    }
}

/// <summary>
///     Creates an instance of the <c>ETGOTMSalesLineWritePostSuperOutputContract</c> class based on a container from a prior call to <c>ETGOTMSalesLineWritePostSuperOutputContract.pack</c> method.
/// </summary>
/// <param name="_packedClass">
///     A <c>Container</c> holding the packed class.
/// </param>
/// <returns>
///     An instance of the <c>ETGOTMSalesLineWritePostSuperOutputContract</c> class identical to the one that was packed into the <c>container</c>.
/// </returns>
static public ETGOTMSalesLineWritePostSuperOutputContract create(container _packedClass)
{
    ETGOTMSalesLineWritePostSuperOutputContract salesLineWritePostSuperOutputContract = ETGOTMSalesLineWritePostSuperOutputContract::construct();
    salesLineWritePostSuperOutputContract.unpack(_packedClass);
    return salesLineWritePostSuperOutputContract;
}
